#!/usr/bin/env python3
import os
import sys
import shutil
import subprocess
from pathlib import Path

ROOT = Path(__file__).resolve().parent
REQUIREMENTS = ROOT / "requirements.txt"
DIST_DIR = ROOT / "dist"
PACKAGE_NAME = os.environ.get("PACKAGE_NAME", ROOT.name)
ARCHIVE_BASE = DIST_DIR / PACKAGE_NAME


def run(cmd, cwd=ROOT):
    print(f"+ {' '.join(cmd)}")
    subprocess.run(cmd, cwd=cwd, check=True)


def install_dependencies():
    if not REQUIREMENTS.exists():
        print(f"requirements.txt not found at {REQUIREMENTS}", file=sys.stderr)
        sys.exit(1)
    run([sys.executable, "-m", "pip", "install", "--disable-pip-version-check", "-r", str(REQUIREMENTS)])


def run_tests():
    pytest_ini = ROOT / "pytest.ini"
    tests_dir = ROOT / "tests"
    if pytest_ini.exists() or tests_dir.exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests detected, skipping.")


def package():
    DIST_DIR.mkdir(exist_ok=True)
    archive = shutil.make_archive(str(ARCHIVE_BASE), "zip", root_dir=ROOT, base_dir=".")
    print(f"Created package: {archive}")


def main():
    install_dependencies()
    run_tests()
    package()
    print("Deployment workflow completed successfully.")


if __name__ == "__main__":
    main()